static get observedAttributes() { return ['label']; }
attributeChangedCallback(name, oldValue, newValue) {
  if (name === 'label') {
    this.button.textContent = newValue;
  }
}

creating_web_component.with_properties:
get value() { return this._value; }
set value(val) {
  this._value = val;
  this.render();
}

